const page = $input.first().json;
// n8n Notion Trigger v1 flattens properties to top-level fields
const title = page['タイトル'] || 'No Title';
const typeVal = page['種別'];
const type = Array.isArray(typeVal) ? typeVal.join(', ') : (typeVal || 'その他');
const detail = page['詳細'] || '';
const sender = page['送信者メールアドレス'] || 'anonymous';
const urgency = page['緊急度'] || 'medium';
const project = page['対象プロジェクト'] || 'その他';
const ts = new Date().toISOString();
const shortId = Math.random().toString(36).substr(2, 8);
const id = `feedback_${ts.replace(/[-:T.Z]/g,'').substr(0,15)}_${shortId}`;
return [{ json: { id, timestamp: ts, sender, feedbackType: type, title, detail, urgency, project, pageId: page.id } }];

// pure Node.js implementation — atomic append to shogun.yaml without python
const fs = require('fs');

const SHOGUN_INBOX = '/home/ubuntu/shogun/queue/inbox/shogun.yaml';

function escapeYamlString(s) {
  return "'" + String(s).replace(/'/g, "''") + "'";
}

function buildContent(data) {
  const lines = [
    '【種別】' + (data.feedbackType || ''),
    '【緊急度】' + (data.urgency || ''),
    '【対象】' + (data.project || ''),
    '【タイトル】' + (data.title || ''),
    '【詳細】' + (data.detail || ''),
  ];
  return lines.join('\n');
}

function buildYamlEntry(data) {
  const id = data.id || 'unknown';
  const timestamp = data.timestamp || '';
  const sender = data.sender || 'anonymous';
  const content = buildContent(data);
  let entry = '- id: ' + escapeYamlString(id) + '\n';
  entry += '  timestamp: ' + escapeYamlString(timestamp) + '\n';
  entry += '  from: ' + escapeYamlString(sender) + '\n';
  entry += '  type: feedback\n';
  entry += '  read: false\n';
  entry += '  content: ' + escapeYamlString(content) + '\n';
  return entry;
}

const data = $input.first().json;
const entryYaml = buildYamlEntry(data);

const current = fs.readFileSync(SHOGUN_INBOX, 'utf8');
let newContent;
if (current.trim() === '' || current.trim() === 'messages:' || current.trim() === 'messages: []') {
  newContent = 'messages:\n' + entryYaml;
} else {
  newContent = current.endsWith('\n') ? current + entryYaml : current + '\n' + entryYaml;
}

// Use Date.now() + random instead of process.pid (process not available in n8n task-runner)
const tmpFile = SHOGUN_INBOX + '.tmp.' + Date.now() + '_' + Math.floor(Math.random() * 100000);
fs.writeFileSync(tmpFile, newContent, 'utf8');
fs.renameSync(tmpFile, SHOGUN_INBOX);

return [{ json: { success: true, id: data.id, message: 'feedback appended (pure Node.js)' } }];

// best-effort error notify — try /usr/bin/bash, fallback to silent
const { execSync } = require('child_process');
let errMsg = ($json.execution && $json.execution.error && $json.execution.error.message) || $json.error || 'unknown error';
errMsg = String(errMsg).replace(/'/g, '').substr(0, 80);
try {
  execSync(`/usr/bin/bash /home/ubuntu/shogun/scripts/ntfy.sh "[vps] feedback-system error: ${errMsg}" "n8n" "error"`, {
    encoding: 'utf-8',
    timeout: 10000
  });
} catch(e) {
  try {
    // fallback: append to a log file directly
    require('fs').appendFileSync('/home/ubuntu/shogun/logs/n8n_feedback_errors.log', `[${new Date().toISOString()}] ${errMsg}\n`, 'utf8');
  } catch(e2) {}
}
return [{ json: $input.first().json }];
